import { DB } from "./countries";

// ─── Categories (declarative) ───
// Each clue is DATA, not code — its test function is generated by buildTest().
// To add a clue, append a spec. Predicate kinds:
//   flag: "<field>"                 → country[field] is truthy (e.g. "brics", "fl_red")
//   num: { field, op, value }       → numeric compare, op is ">" | "<" | "="
//   continents: ["Europe", ...]     → country.continent is one of these
//   startsWith: "S" | "vowel"       → name-based (prefix the id with "start" so it is
//                                      auto-excluded from Practice, where the name shows)
//   test: (country) => boolean      → escape hatch for anything custom
// Common fields: continent, gdp (k USD/cap), tz (time zones), pop (millions), plus the
// boolean tags from countries.json (locked, isle, monarchy, fl_red, brics, nuclear, …).
const SPECS=[
  {id:"europe",l:"In Europe",i:"🌍",d:1,continents:["Europe"]},
  {id:"asia",l:"In Asia",i:"🌏",d:1,continents:["Asia"]},
  {id:"africa",l:"In Africa",i:"🌍",d:1,continents:["Africa"]},
  {id:"americas",l:"In Americas",i:"🌎",d:1,continents:["North America","South America"]},
  {id:"locked",l:"Landlocked",i:"⛰️",d:1,flag:"locked"},
  {id:"island",l:"Island Nation",i:"🏝️",d:1,flag:"isle"},
  {id:"left",l:"Drives Left",i:"🚗",d:2,flag:"left"},
  {id:"gdp40k",l:"GDP/Cap > $40K",i:"💰",d:3,num:{field:"gdp",op:">",value:40}},
  {id:"gdp20k",l:"GDP/Cap > $20K",i:"💸",d:2,num:{field:"gdp",op:">",value:20}},
  {id:"monarchy",l:"Is a Monarchy",i:"👑",d:2,flag:"monarchy"},
  {id:"pmHead",l:"PM Leads Govt",i:"🏛️",d:3,flag:"pm"},
  {id:"unFound",l:"UN Founder '45",i:"🕊️",d:3,flag:"un"},
  {id:"inEU",l:"In the EU",i:"🇪🇺",d:2,flag:"eu"},
  {id:"inNATO",l:"In NATO",i:"🛡️",d:2,flag:"nato"},
  {id:"g20",l:"In the G20",i:"🌐",d:3,flag:"g20"},
  {id:"cwlth",l:"Commonwealth",i:"🤝",d:2,flag:"cwlth"},
  {id:"flStars",l:"Flag Has Stars",i:"⭐",d:2,flag:"fl_stars"},
  {id:"flCrescent",l:"Flag: Crescent",i:"☪️",d:3,flag:"fl_crescent"},
  {id:"flAnimal",l:"Flag: Animal",i:"🦁",d:3,flag:"fl_animal"},
  {id:"flCross",l:"Flag: Cross",i:"✝️",d:3,flag:"fl_cross"},
  {id:"olympics",l:"Hosted Olympics",i:"🏅",d:3,flag:"olympics"},
  {id:"fifaWC",l:"Hosted FIFA WC",i:"⚽",d:3,flag:"fifa"},
  {id:"f1gp",l:"Hosted F1 GP",i:"🏎️",d:2,flag:"f1gp"},
  {id:"eng",l:"English Official",i:"🗣️",d:1,flag:"eng"},
  {id:"fre",l:"French Official",i:"🗣️",d:2,flag:"fr"},
  {id:"esp",l:"Spanish Official",i:"🗣️",d:2,flag:"es"},
  {id:"pop50",l:"Pop > 50M",i:"👥",d:2,num:{field:"pop",op:">",value:50}},
  {id:"conflict",l:"Conflict Post-2000",i:"⚠️",d:3,flag:"conflict"},
  {id:"soviet",l:"Was Soviet",i:"☭",d:3,flag:"soviet"},
  {id:"flRed",l:"Flag Has Red",i:"🔴",d:1,flag:"fl_red"},
  {id:"flBlue",l:"Flag Has Blue",i:"🔵",d:1,flag:"fl_blue"},
  {id:"flGreen",l:"Flag Has Green",i:"🟢",d:2,flag:"fl_green"},
  {id:"flText",l:"Flag Has Text",i:"✍️",d:3,flag:"fl_text"},
  {id:"federal",l:"Federal State",i:"🏙️",d:2,flag:"federal"},
  {id:"brics",l:"In BRICS",i:"🧱",d:3,flag:"brics"},
  {id:"opec",l:"In OPEC",i:"🛢️",d:3,flag:"opec"},
  {id:"asean",l:"In ASEAN",i:"🌴",d:3,flag:"asean"},
  {id:"conscript",l:"Has Conscription",i:"🎖️",d:2,flag:"conscript"},
  {id:"arabic",l:"Arabic Official",i:"🗣️",d:2,flag:"ar"},
  {id:"nuclear",l:"Nuclear Power",i:"☢️",d:3,flag:"nuclear"},
  {id:"pop100",l:"Pop > 100M",i:"👨‍👩‍👧‍👦",d:2,num:{field:"pop",op:">",value:100}},
  {id:"popSmall",l:"Pop Under 1M",i:"🤏",d:2,num:{field:"pop",op:"<",value:1}},
  {id:"multiTz",l:"Multiple Time Zones",i:"🕐",d:2,num:{field:"tz",op:">",value:1}},
  {id:"gdpLow",l:"GDP/Cap < $2K",i:"🪙",d:2,num:{field:"gdp",op:"<",value:2}},
  {id:"startVowel",l:"Starts With Vowel",i:"🔤",d:1,startsWith:"vowel"},
  {id:"startS",l:"Starts with S",i:"🔤",d:1,startsWith:"S"},
  {id:"startC",l:"Starts with C",i:"🔤",d:1,startsWith:"C"},
  {id:"startB",l:"Starts with B",i:"🔤",d:1,startsWith:"B"},
  {id:"startM",l:"Starts with M",i:"🔤",d:1,startsWith:"M"},
];

function buildTest(s){
  if(s.flag) return c=>!!c[s.flag];
  if(s.num){const{field,op,value}=s.num; if(op===">")return c=>c[field]>value; if(op==="<")return c=>c[field]<value; return c=>c[field]===value;}
  if(s.continents) return c=>s.continents.includes(c.continent);
  if(s.startsWith) return s.startsWith==="vowel"?c=>"AEIOU".includes(c.name[0]):c=>c.name[0]===s.startsWith;
  return s.test||(()=>false);
}

// Runtime shape kept identical to before: { l, i, d, t }.
export const CATS=Object.fromEntries(SPECS.map(s=>[s.id,{l:s.l,i:s.i,d:s.d,t:buildTest(s)}]));

// Canonical ordered list of all category IDs (spec order).
export const CAT_KEYS=SPECS.map(s=>s.id);

// Precompute members per category for speed.
export const CAT_MEMBERS={};
CAT_KEYS.forEach(k=>{CAT_MEMBERS[k]=DB.filter(c=>CATS[k].t(c));});

// Categories usable in Practice modes (name-based ones excluded).
export const QF_CATS=CAT_KEYS.filter(k=>!k.startsWith("start"));
